function solve(s) {
    const segments = [];
    const seen = new Set();
    let start = 0;
    while (start < s.length) {
        let current = '';
        while (start < s.length) {
            current += s[start];
            if (!seen.has(current)) {
                seen.add(current);
                segments.push(current);
                start++;
                break;
            } else {
                start++;
            }
        }
    }
    return segments;
}

